import{_ as o,a,b as t,c as i,d}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as r}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as n,o as l,c,a2 as s}from"./chunks/framework.DnrXFDHb.js";const j=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/Other/ocr.md","filePath":"pl-PL/Other/ocr.md","lastUpdated":1781962217000}'),p={name:"pl-PL/Other/ocr.md"};function z(u,e,y,k,w,h){return l(),c("div",null,[...e[0]||(e[0]=[s('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR wyciąga tekst z obrazów, skanów i zrzutów ekranu dokumentów.</p><p>Po rozpoznaniu możesz skopiować wynik, wyeksportować go jako <code>Markdown</code>, <code>PDF</code> lub <code>Word</code>, albo pobrać kilka formatów razem w paczce.</p><h2 id="co-potrafi-ocr" tabindex="-1">Co potrafi OCR <a class="header-anchor" href="#co-potrafi-ocr" aria-label="Permalink to &quot;Co potrafi OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funkcja</th><th>Opis</th></tr></thead><tbody><tr><td>Rozpoznawanie tekstu z obrazu</td><td>Wyciąga tekst z obrazów, screenshotów i skanów.</td></tr><tr><td>Rozpoznawanie układu dokumentu</td><td>Lepsze dla tabel, formuł, pieczątek i mieszanych układów tekst-obraz.</td></tr><tr><td>Wiele usług</td><td>Obsługuje Baidu PaddleOCR, Microsoft Azure Vision i Google Vision.</td></tr><tr><td>Kopiowanie wyników</td><td>Pozwala skopiować rozpoznany tekst po przetworzeniu.</td></tr><tr><td>Eksport plików</td><td>Eksportuje <code>Markdown</code>, <code>PDF</code> i <code>Word</code>.</td></tr><tr><td>Pakowanie zbiorcze</td><td>Po rozpoznaniu wielu plików pobiera wyniki jako paczkę.</td></tr></tbody></table><h2 id="najpierw-skonfiguruj-usługi-ocr" tabindex="-1">Najpierw skonfiguruj usługi OCR <a class="header-anchor" href="#najpierw-skonfiguruj-usługi-ocr" aria-label="Permalink to &quot;Najpierw skonfiguruj usługi OCR&quot;">​</a></h2><p>Otwórz:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+o+'" alt="Geolokalizacja IP i OCR" loading="lazy"></p><p>Wypełnij dane usług, których chcesz użyć:</p><table tabindex="0"><thead><tr><th>Usługa</th><th>Co wpisać</th><th>Najlepsze do</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>Zalecany pierwszy wybór. Dobry dla dokumentów, obrazów, tabel i mieszanych układów.</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> i <code>Azure Vision API Key</code></td><td>Przydatne, jeśli używasz już usług chmurowych Microsoft.</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>. Service account <code>JSON</code> służy tylko do zapytania o limit.</td><td>Przydatne, jeśli używasz Google Cloud.</td></tr></tbody></table><p>Po wpisaniu danych zapisz ustawienia.</p><p>Do pierwszego testu możesz skonfigurować tylko jedną usługę. Nie potrzebujesz wszystkich trzech.</p><h2 id="konfiguracja-google-vision" tabindex="-1">Konfiguracja Google Vision <a class="header-anchor" href="#konfiguracja-google-vision" aria-label="Permalink to &quot;Konfiguracja Google Vision&quot;">​</a></h2><p>Konfiguracja Google ma dwie części:</p><table tabindex="0"><thead><tr><th>Cel</th><th>Wymaganie</th></tr></thead><tbody><tr><td>Używanie OCR</td><td>Włącz <code>Cloud Vision API</code>, potem utwórz <code>API Key</code>.</td></tr><tr><td>Zapytanie o użycie</td><td>Utwórz service account, nadaj <code>Monitoring Viewer</code>, potem pobierz service account <code>JSON</code>.</td></tr></tbody></table><p><img src="'+r+'" alt="Google API key i service account" loading="lazy"></p><h3 id="uzywanie-google-do-ocr" tabindex="-1">Używanie Google do OCR <a class="header-anchor" href="#uzywanie-google-do-ocr" aria-label="Permalink to &quot;Używanie Google do OCR&quot;">​</a></h3><ol><li>Otwórz Google Cloud Console.</li><li>Przejdź do <code>APIs &amp; Services</code>.</li><li>Otwórz <code>Library</code>, wyszukaj <code>Cloud Vision API</code> i włącz.</li><li>Wróć do <code>Credentials</code>.</li><li>Utwórz <code>API Key</code>.</li><li>Otwórz API Key i skopiuj go.</li><li>Wklej do <code>Google Vision API Key</code> w ImgBed.</li><li>Zapisz.</li></ol><p>Potem możesz wybrać Google Vision w oknie OCR.</p><h3 id="zapytanie-o-uzycie-google" tabindex="-1">Zapytanie o użycie Google <a class="header-anchor" href="#zapytanie-o-uzycie-google" aria-label="Permalink to &quot;Zapytanie o użycie Google&quot;">​</a></h3><p>Zapytanie o limit nie jest wymagane do rozpoznawania.</p><p>Pokazuje tylko orientacyjnie, ile wywołań Google Vision użyto w ostatnich 30 dniach.</p><ol><li>W Google Cloud Console otwórz <code>IAM &amp; Admin</code>.</li><li>Otwórz <code>Service Accounts</code>.</li><li>Utwórz service account, np. <code>vision-monitor</code>.</li><li>Nadaj mu rolę <code>Monitoring Viewer</code>.</li><li>Otwórz szczegóły service account i utwórz klucz.</li><li>Wybierz <code>JSON</code>.</li><li>Pobierz wygenerowany plik JSON.</li><li>Wróć do ImgBed i zaimportuj go jako service account <code>JSON</code> (opcjonalnie).</li><li>Po udanym imporcie kliknij zapytanie o limit.</li></ol><p>Po imporcie ImgBed pokazuje nazwę projektu, do którego należy service account. Podczas zapytania odczytuje dane Google monitoring i pokazuje liczbę wywołań w bieżącym miesiącu.</p><p>W skrócie:</p><table tabindex="0"><thead><tr><th>Element</th><th>Cel</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>Wykonuje rozpoznawanie OCR.</td></tr><tr><td>Service account <code>JSON</code></td><td>Odpytuje liczbę użytych wywołań Google Vision.</td></tr><tr><td>Rola <code>Monitoring Viewer</code></td><td>Pozwala service account czytać dane użycia.</td></tr></tbody></table><h2 id="pobieranie-tokenu-baidu-paddleocr" tabindex="-1">Pobieranie tokenu Baidu PaddleOCR <a class="header-anchor" href="#pobieranie-tokenu-baidu-paddleocr" aria-label="Permalink to &quot;Pobieranie tokenu Baidu PaddleOCR&quot;">​</a></h2><p>Baidu PaddleOCR wymaga access token.</p><p><img src="'+a+'" alt="Pobieranie tokenu PaddleOCR" loading="lazy"></p><p>Otwórz okno wywołania <code>API</code> na stronie Baidu PaddleOCR, kliknij pobranie tokenu i skopiuj go.</p><p>Wróć do ImgBed, wklej do <code>PaddleOCR Token</code> i zapisz.</p><h2 id="rozpoczecie-rozpoznawania" tabindex="-1">Rozpoczęcie rozpoznawania <a class="header-anchor" href="#rozpoczecie-rozpoznawania" aria-label="Permalink to &quot;Rozpoczęcie rozpoznawania&quot;">​</a></h2><p>W Zarządzaniu plikami wybierz obraz lub zrzut ekranu dokumentu i kliknij <code>OCR</code>.</p><p><img src="'+t+'" alt="Rozpoznawanie OCR" loading="lazy"></p><p>W oknie wybierz usługę rozpoznawania i model.</p><p>Popularne modele PaddleOCR:</p><table tabindex="0"><thead><tr><th>Model</th><th>Najlepsze do</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>Zalecany domyślnie. Dobry dla dokumentów, tabel, formuł, pieczątek i mieszanych układów.</td></tr><tr><td><code>PP-OCRv5</code></td><td>Proste obrazy, zwykły tekst i lekkie rozpoznawanie.</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>Wielojęzyczne, złożone obrazy i treści podobne do wykresów.</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>Bardziej złożone strony dokumentów i odtwarzanie układu.</td></tr></tbody></table><p>Jeśli nie masz pewności, zacznij od <code>PP-StructureV3</code>.</p><h2 id="opcje-zaawansowane" tabindex="-1">Opcje zaawansowane <a class="header-anchor" href="#opcje-zaawansowane" aria-label="Permalink to &quot;Opcje zaawansowane&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opcja</th><th>Opis</th></tr></thead><tbody><tr><td>Korekcja orientacji</td><td>Użyj, gdy obraz jest obrócony lub przekrzywiony.</td></tr><tr><td>Prostowanie dokumentu</td><td>Użyj dla fotografowanych dokumentów z krzywizną lub perspektywą.</td></tr><tr><td>Wykrywanie układu</td><td>Użyj, gdy chcesz zachować nagłówki, akapity, tabele i strukturę obrazu.</td></tr><tr><td>Rozpoznawanie wykresów</td><td>Użyj, gdy obraz zawiera wykresy lub złożone struktury.</td></tr><tr><td>Upiększ <code>Markdown</code></td><td>Sprawia, że eksportowany Markdown jest czytelniejszy.</td></tr></tbody></table><p>Dla zwykłych screenshotów zostaw minimalne opcje. Dla skanów dokumentów włącz więcej opcji dokumentowych.</p><h2 id="wyniki" tabindex="-1">Wyniki <a class="header-anchor" href="#wyniki" aria-label="Permalink to &quot;Wyniki&quot;">​</a></h2><p>Po zakończeniu rozpoznawania okno pokaże wynik.</p><p>Możesz go skopiować bezpośrednio albo wybrać format eksportu.</p><p><img src="'+i+'" alt="Rozpoznawanie PDF" loading="lazy"></p><p>Dla stron dokumentów eksportowany <code>PDF</code> może zachować wygląd strony i jednocześnie pozwolić na wyszukiwanie tekstu. To przydatne do archiwizacji skanów i późniejszego odnajdywania treści.</p><h2 id="wybor-formatu-eksportu" tabindex="-1">Wybór formatu eksportu <a class="header-anchor" href="#wybor-formatu-eksportu" aria-label="Permalink to &quot;Wybór formatu eksportu&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Najlepsze do</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>Notatki, systemy dokumentacji i późniejsza edycja.</td></tr><tr><td><code>PDF (.pdf)</code></td><td>Zachowanie wyglądu strony i wyników skanowania.</td></tr><tr><td><code>Word (.docx)</code></td><td>Dalsza edycja układu, tekstu i przekazanie innym.</td></tr><tr><td>Eksport wszystkiego</td><td>Zapisuje wiele formatów i oryginalny obraz, dobre dla ważnych archiwów.</td></tr></tbody></table><p>Jeśli potrzebujesz tylko tekstu, eksportuj Markdown.</p><p>Jeśli potrzebujesz wyglądu strony, użyj PDF lub Word.</p><h2 id="wynik-word" tabindex="-1">Wynik Word <a class="header-anchor" href="#wynik-word" aria-label="Permalink to &quot;Wynik Word&quot;">​</a></h2><p>Wyeksportowane dokumenty Word można otwierać i edytować w pakietach biurowych.</p><p><img src="'+d+`" alt="Wynik Word" loading="lazy"></p><p>Niektóre dokumenty zawierają w wyniku Word rozpoznane obrazy, nagłówki i akapity.</p><p>Jakość rozpoznania zależy od ostrości oryginału, wyboru modelu i złożoności dokumentu.</p><h2 id="najlepsze-typy-plikow-do-ocr" tabindex="-1">Najlepsze typy plików do OCR <a class="header-anchor" href="#najlepsze-typy-plikow-do-ocr" aria-label="Permalink to &quot;Najlepsze typy plików do OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Typ pliku</th><th>Rekomendacja</th></tr></thead><tbody><tr><td>Wyraźne screenshoty</td><td>Rozpoznawaj bezpośrednio.</td></tr><tr><td>Skany</td><td>Preferuj <code>PP-StructureV3</code>.</td></tr><tr><td>Fotografowane dokumenty</td><td>Włącz korekcję orientacji i prostowanie dokumentu.</td></tr><tr><td>Tabele, formuły, pieczątki</td><td>Preferuj modele strukturalne.</td></tr><tr><td>Proste obrazy z krótkim tekstem</td><td><code>PP-OCRv5</code> zwykle wystarczy.</td></tr></tbody></table><p>Wyraźniejsze obrazy z prostszym tekstem zwykle dają lepsze wyniki.</p><h2 id="typowe-przypadki" tabindex="-1">Typowe przypadki <a class="header-anchor" href="#typowe-przypadki" aria-label="Permalink to &quot;Typowe przypadki&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Przypadek</th><th>Znaczenie</th></tr></thead><tbody><tr><td>Rozpoznawanie się nie udaje</td><td>Sprawdź, czy token lub key usługi został zapisany.</td></tr><tr><td>Rozpoznawanie jest wolne</td><td>Złożone dokumenty i duże obrazy wymagają więcej czasu.</td></tr><tr><td>Tabela jest niepełna</td><td>Spróbuj modelu strukturalnego.</td></tr><tr><td>Tekst ma błędy</td><td>Rozmycie, odblaski i przekrzywienie zwiększają liczbę błędów. Spróbuj wyraźniejszego obrazu.</td></tr><tr><td>Wynik Word zawiera wiele obrazów</td><td>Modele strukturalne mogą zachować część rozpoznanych obrazów. To normalne.</td></tr></tbody></table><h3 id="zapytanie-o-limit-google-nie-działa" tabindex="-1">Zapytanie o limit Google nie działa <a class="header-anchor" href="#zapytanie-o-limit-google-nie-działa" aria-label="Permalink to &quot;Zapytanie o limit Google nie działa&quot;">​</a></h3><p>Sprawdź:</p><ol><li>Zaimportowano service account <code>JSON</code>.</li><li>Service account ma rolę <code>Monitoring Viewer</code>.</li><li><code>Cloud Vision API</code> jest włączone dla projektu.</li></ol><p>Jeśli potrzebujesz tylko OCR, a nie zapytania o użycie, możesz pominąć service account JSON i wypełnić tylko <code>Google Vision API Key</code>.</p><h2 id="szybki-przebieg" tabindex="-1">Szybki przebieg <a class="header-anchor" href="#szybki-przebieg" aria-label="Permalink to &quot;Szybki przebieg&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Otwórz System Settings</span></span>
<span class="line"><span>-&gt; Otwórz Other Settings</span></span>
<span class="line"><span>-&gt; Wpisz dane usługi OCR</span></span>
<span class="line"><span>-&gt; Zapisz</span></span>
<span class="line"><span>-&gt; Wróć do Zarządzania plikami</span></span>
<span class="line"><span>-&gt; Wybierz plik i kliknij OCR</span></span>
<span class="line"><span>-&gt; Wybierz model</span></span>
<span class="line"><span>-&gt; Poczekaj na rozpoznanie</span></span>
<span class="line"><span>-&gt; Skopiuj wynik albo eksportuj Markdown / PDF / Word</span></span></code></pre></div>`,67)])])}const P=n(p,[["render",z]]);export{j as __pageData,P as default};
